K=$(grep -E '^N8N_API_KEY=' /root/Iryna_Karmazina/.env | tail -1 | cut -d= -f2-); for id in JQKA35haUsXU4XqE zVlHFJCe0Afy0kMU; do curl -s -m 25 -H "X-N8N-API-KEY: $K" "https://irynakarmazina.app.n8n.cloud/api/v1/workflows/$id" -o /tmp/w_$id.json; done; python3 - <<'PY'
import json
for wid in ['JQKA35haUsXU4XqE','zVlHFJCe0Afy0kMU']:
    try: d=json.load(open('/tmp/w_'+wid+'.json'))
    except Exception as e: print('ERR',wid,e); continue
    print('==== ',wid,'|',d.get('name'),'| active=',d.get('active'))
    for n in d.get('nodes',[]):
        p=n.get('parameters',{}) or {}
        def g(k):
            v=p.get(k)
            if isinstance(v,dict): return v.get('value') or v.get('mode')
            return v
        info={k:g(k) for k in ('path','httpMethod','url','operation','documentId','sheetName') if k in p}
        print(' -',n.get('name'),'|',n.get('type'),'|',info)
PY
